pub(crate) fn any_specified_encoding(sequence: &[u8], search_zone: usize) -> Option<String> {
    let seq_len = sequence.len();
    let search_zone = std::cmp::min(seq_len, search_zone);

    let decoded = decode(
        &sequence[..search_zone],
        "ascii",
        DecoderTrap::Ignore,
        false,
        false,
    )
    .unwrap_or_default();

    let results: Vec<String> = RE_POSSIBLE_ENCODING_INDICATION
        .captures_iter(&decoded)
        .filter_map(|cap| cap.get(1).map(|m| m.as_str().to_string()))
        .collect();

    if results.is_empty() {
        return None;
    }

    for raw in results {
        let normalized = raw.to_lowercase();
        // first try the canonical dash variant
        let spec_dash = normalized.replace("_", "-");
        // then try the underscore variant
        let spec_under = normalized.replace("-", "_");
        // special-case Python alias for iso_8859_1
        if spec_under == "iso_8859_1" {
            return Some("latin_1".to_string());
        }
        if let Some(encoding_iana) = iana_name(&spec_dash) {
            return Some(encoding_iana.to_string());
        }
        if let Some(encoding_iana) = iana_name(&spec_under) {
            return Some(encoding_iana.to_string());
        }
    }

    None
}

