use crate::entity::{CharsetMatch, CharsetMatches, CoherenceMatch, Language};

#[test]
fn test_iter_empty() {
    // Empty CharsetMatches yields no items
    let cm = CharsetMatches::new(None);
    let mut count = 0;
    for _ in cm.iter() {
        count += 1;
    }
    assert_eq!(count, 0);
}

#[test]
fn test_iter_contents() {
    // Create two CharsetMatch instances with minimal parameters
    let lang = CoherenceMatch { language: &Language::English, score: 1.0 };
    let m1 = CharsetMatch::new(b"a", "utf-8", 0.0, false, &vec![lang.clone()], Some("a"));
    let m2 = CharsetMatch::new(b"b", "utf-8", 0.0, false, &vec![lang.clone()], Some("b"));
    let cm = CharsetMatches::new(Some(vec![m1.clone(), m2.clone()]));
    // Direct iteration collects references
    let items: Vec<&CharsetMatch> = cm.iter().collect();
    assert_eq!(items.len(), 2);
    assert_eq!(items[0], &m1);
    assert_eq!(items[1], &m2);
    // Ensure multiple iterations yield same results
    let items2: Vec<&CharsetMatch> = cm.iter().collect();
    assert_eq!(items, items2);
}

