pub fn multi_byte_usage(&self) -> f32 {
    let s = self.decoded_payload().expect("UTF-8 decoding failed");
    let char_count = s.chars().count() as f32;
    let byte_count = self.payload.len() as f32;
    1.0 - (char_count / byte_count)
}

