// Tests for CharsetMatches.get_best
use crate::entity::{CharsetMatch, CharsetMatches};

fn make_cm(mean: f32) -> CharsetMatch {
    CharsetMatch::new(b"x", "utf-8", mean, false, &vec![], Some("x"))
}

#[test]
fn test_get_best_empty() {
    let cmatches = CharsetMatches::new(None);
    assert!(cmatches.get_best().is_none());
}

#[test]
fn test_get_best_single() {
    let cm = make_cm(0.5);
    let cmatches = CharsetMatches::new(Some(vec![cm.clone()]));
    let best = cmatches.get_best();
    assert!(best.is_some());
    assert_eq!(best.unwrap().encoding(), cm.encoding());
}

#[test]
fn test_get_best_multiple() {
    let cm1 = make_cm(0.1);
    let cm2 = make_cm(0.2);
    // input reversed to test sorting
    let cmatches = CharsetMatches::new(Some(vec![cm2.clone(), cm1.clone()]));
    let best = cmatches.get_best().unwrap();
    assert_eq!(best.encoding(), cm1.encoding());
    // Compare chaos (mean mess ratio) values
    assert!((best.chaos() - cm1.chaos()).abs() < f32::EPSILON);
}
